package server

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// TestListProviders verifies GET /api/providers returns a JSON array containing
// all known harnesses.
func TestListProviders(t *testing.T) {
	dir := setupTestDir(t)
	srv := New(":0", dir)

	req := httptest.NewRequest(http.MethodGet, "/api/providers", nil)
	req.RemoteAddr = "127.0.0.1:12345"
	w := httptest.NewRecorder()
	srv.Handler().ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Fatalf("expected 200, got %d", w.Code)
	}

	var items []ProviderSummary
	if err := json.NewDecoder(w.Body).Decode(&items); err != nil {
		t.Fatalf("decode: %v", err)
	}
	if len(items) == 0 {
		t.Fatal("expected non-empty provider list")
	}

	// Verify required fields are present and not fabricated as "ok"/"0" when unknown.
	svc, err := agent.NewServiceFromWorkDir(dir)
	if err != nil {
		t.Fatalf("NewServiceFromWorkDir: %v", err)
	}
	infos, err := svc.ListHarnesses(context.Background())
	if err != nil {
		t.Fatalf("ListHarnesses: %v", err)
	}
	harnessNames := map[string]bool{}
	for _, info := range infos {
		harnessNames[info.Name] = true
	}

	for _, item := range items {
		if item.Harness == "" {
			t.Error("provider summary missing harness field")
		}
		if !harnessNames[item.Harness] {
			t.Errorf("unexpected harness in response: %q", item.Harness)
		}
		if item.DisplayName == "" {
			t.Errorf("harness %q missing display_name", item.Harness)
		}
		// Status must be one of the defined values.
		switch item.Status {
		case "available", "unavailable", "unknown":
		default:
			t.Errorf("harness %q has invalid status %q", item.Harness, item.Status)
		}
		// AuthState must be one of the defined values.
		switch item.AuthState {
		case "authenticated", "unauthenticated", "unknown":
		default:
			t.Errorf("harness %q has invalid auth_state %q", item.Harness, item.AuthState)
		}
		// QuotaHeadroom must be one of the defined values.
		switch item.QuotaHeadroom {
		case "ok", "blocked", "unknown":
		default:
			t.Errorf("harness %q has invalid quota_headroom %q", item.Harness, item.QuotaHeadroom)
		}
		// SignalSources must contain at least "none" when no signals available.
		if len(item.SignalSources) == 0 {
			t.Errorf("harness %q has empty signal_sources (should be at least [none])", item.Harness)
		}
		// CostClass must not be empty.
		if item.CostClass == "" {
			t.Errorf("harness %q missing cost_class", item.Harness)
		}
		// LastCheckedTS must be present.
		if item.LastCheckedTS == "" {
			t.Errorf("harness %q missing last_checked_ts", item.Harness)
		}
	}

	// All harnesses in the registry must appear in the response.
	found := map[string]bool{}
	for _, item := range items {
		found[item.Harness] = true
	}
	for name := range harnessNames {
		if !found[name] {
			t.Errorf("harness %q missing from provider list response", name)
		}
	}
}

// TestShowProvider verifies GET /api/providers/{harness} returns a full detail
// object for a known harness.
func TestShowProvider(t *testing.T) {
	dir := setupTestDir(t)
	srv := New(":0", dir)

	req := httptest.NewRequest(http.MethodGet, "/api/providers/claude", nil)
	req.RemoteAddr = "127.0.0.1:12345"
	w := httptest.NewRecorder()
	srv.Handler().ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Fatalf("expected 200, got %d: %s", w.Code, w.Body.String())
	}

	var detail ProviderDetail
	if err := json.NewDecoder(w.Body).Decode(&detail); err != nil {
		t.Fatalf("decode: %v", err)
	}

	if detail.Harness != "claude" {
		t.Errorf("expected harness=claude, got %q", detail.Harness)
	}
	if detail.DisplayName == "" {
		t.Error("missing display_name")
	}
	// Status must be one of the defined values.
	switch detail.Status {
	case "available", "unavailable", "unknown":
	default:
		t.Errorf("invalid status %q", detail.Status)
	}
	// AuthState — in test env with no stats-cache, should be "unknown".
	switch detail.AuthState {
	case "authenticated", "unauthenticated", "unknown":
	default:
		t.Errorf("invalid auth_state %q", detail.AuthState)
	}
	// Models array must be present (may be empty).
	if detail.Models == nil {
		t.Error("models field must not be nil (should be empty array when no models)")
	}
	// SignalSources must contain at least one entry.
	if len(detail.SignalSources) == 0 {
		t.Error("signal_sources must not be empty")
	}
	// RoutingSignals.Performance must carry -1 sentinels when no samples.
	perf := detail.RoutingSignals.Performance
	if perf.SampleCount == 0 {
		if perf.SuccessRate != -1 {
			t.Errorf("success_rate should be -1 when sample_count=0, got %v", perf.SuccessRate)
		}
		if perf.P50LatencyMS != -1 {
			t.Errorf("p50_latency_ms should be -1 when sample_count=0, got %v", perf.P50LatencyMS)
		}
		if perf.P95LatencyMS != -1 {
			t.Errorf("p95_latency_ms should be -1 when sample_count=0, got %v", perf.P95LatencyMS)
		}
	}
	// Window must be "7d".
	if perf.Window != "7d" {
		t.Errorf("performance.window should be 7d, got %q", perf.Window)
	}
}

// TestShowProviderNotFound verifies GET /api/providers/{unknown} returns 404.
func TestShowProviderNotFound(t *testing.T) {
	dir := setupTestDir(t)
	srv := New(":0", dir)

	req := httptest.NewRequest(http.MethodGet, "/api/providers/nonexistent-harness", nil)
	req.RemoteAddr = "127.0.0.1:12345"
	w := httptest.NewRecorder()
	srv.Handler().ServeHTTP(w, req)

	if w.Code != http.StatusNotFound {
		t.Fatalf("expected 404, got %d", w.Code)
	}
}

// TestProviderUnknownStateContract verifies that unknown fields carry "unknown"
// or -1 sentinels, not fabricated "ok"/"0" values (FEAT-014 zero-fabrication).
func TestProviderUnknownStateContract(t *testing.T) {
	dir := setupTestDir(t)
	srv := New(":0", dir)

	// Test each harness that will have no signal data in the test environment.
	for _, harnessName := range []string{"claude", "codex", "gemini"} {
		req := httptest.NewRequest(http.MethodGet, "/api/providers/"+harnessName, nil)
		req.RemoteAddr = "127.0.0.1:12345"
		w := httptest.NewRecorder()
		srv.Handler().ServeHTTP(w, req)

		if w.Code != http.StatusOK {
			t.Errorf("%s: expected 200, got %d", harnessName, w.Code)
			continue
		}

		var detail ProviderDetail
		if err := json.NewDecoder(w.Body).Decode(&detail); err != nil {
			t.Errorf("%s: decode error: %v", harnessName, err)
			continue
		}

		// quota_headroom must not be fabricated as "ok" when there's no signal.
		// It may be "unknown" or "ok" only if there genuinely is signal data.
		if detail.AuthState == "unauthenticated" {
			// This is valid but unlikely in a test — flag it for investigation.
			t.Logf("%s: auth_state=unauthenticated (unexpected in test env)", harnessName)
		}

		// Verify signal_sources contains valid values only.
		validSources := map[string]bool{
			"native-session-jsonl": true,
			"stats-cache":          true,
			"ddx-metrics":          true,
			"none":                 true,
		}
		for _, src := range detail.SignalSources {
			if !validSources[src] {
				t.Errorf("%s: invalid signal_source value %q", harnessName, src)
			}
		}

		// Performance sentinels: when no data, must be -1 not 0.
		perf := detail.RoutingSignals.Performance
		if perf.SampleCount < 3 {
			if perf.SuccessRate != -1 {
				t.Errorf("%s: success_rate must be -1 when sample_count<3, got %v", harnessName, perf.SuccessRate)
			}
		}
	}
}

func TestProviderQuotaStatusTranslationFromHarnessInfo(t *testing.T) {
	now := time.Date(2026, 4, 21, 1, 0, 0, 0, time.UTC)

	cases := []struct {
		name          string
		status        string
		fresh         bool
		wantHeadroom  string
		wantAuthState string
		wantFreshness string
	}{
		{
			name:          "ok fresh",
			status:        "ok",
			fresh:         true,
			wantHeadroom:  "ok",
			wantAuthState: "authenticated",
			wantFreshness: "fresh",
		},
		{

			UsedPercent:   w.UsedPercent,
			ResetsAt:      w.ResetsAt,
			ResetsAtUnix:  w.ResetsAtUnix,
			State:         w.State,
		}
		translatedWindows = append(translatedWindows, qw)
		if w.LimitID == "extra" {
			continue
		}
		if w.State == "blocked" {
			state = "blocked"
			resetsAt = w.ResetsAt
		}
		if w.UsedPercent > float64(usedPercent) {
			usedPercent = int(w.UsedPercent + 0.5)
			windowMinutes = w.WindowMinutes
		}
	}
	snap.QuotaWindows = translatedWindows

	freshness := "fresh"
	if !info.Quota.Fresh {
		freshness = "stale"
	}
	if info.Quota.Status == "unavailable" || info.Quota.Status == "unauthenticated" {
		freshness = "unknown"
	}

	kind := info.Quota.Source
	if kind == "" {
		kind = "stats-cache"
	}

	var ageSeconds int64
	if !info.Quota.CapturedAt.IsZero() {
		if age := now.UTC().Sub(info.Quota.CapturedAt.UTC()); age > 0 {
			ageSeconds = int64(age.Seconds())
		}
	}

	meta := agent.SignalSourceMetadata{
		Provider:   info.Name,
		Kind:       kind,
		ObservedAt: info.Quota.CapturedAt.UTC(),
		Freshness:  freshness,
		AgeSeconds: ageSeconds,
	}
	snap.Source = meta
	snap.CurrentQuota = agent.QuotaSignal{
		Source:        meta,
		State:         state,
		UsedPercent:   usedPercent,
		WindowMinutes: windowMinutes,
		ResetsAt:      resetsAt,
	}

	for _, u := range info.UsageWindows {
		snap.HistoricalUsage.InputTokens += u.InputTokens
		snap.HistoricalUsage.OutputTokens += u.OutputTokens
		snap.HistoricalUsage.TotalTokens += u.TotalTokens
	}
	snap.HistoricalUsage.Source = meta

	return snap
}

func buildProviderSummary(
	info agentlib.HarnessInfo,
	signal agent.RoutingSignalSnapshot,
	outcomes []agent.RoutingOutcome,
	now time.Time,
) ProviderSummary {
	harnessOutcomes := filterProviderOutcomes(outcomes, info.Name, now, 7)
	perf := computeProviderPerformance(harnessOutcomes)
	sources := collectProviderSignalSources(signal, len(harnessOutcomes) > 0)

	var freshnessTS string
	if ts := providerFreshnessTS(signal, harnessOutcomes); !ts.IsZero() {
		freshnessTS = ts.UTC().Format(time.RFC3339)
	}

	return ProviderSummary{
		Harness:            info.Name,
		DisplayName:        harnessDisplayName(info.Name),
		Status:             providerStatusStrInfo(info),
		AuthState:          providerAuthStateStr(signal),
		QuotaHeadroom:      providerQuotaHeadroomStr(signal),
		SignalSources:      sources,
		FreshnessTS:        freshnessTS,
		LastCheckedTS:      now.UTC().Format(time.RFC3339),
		RecentSuccessRate:  perf.SuccessRate,
		RecentLatencyP50MS: perf.P50LatencyMS,
		CostClass:          harnessCosCostClassStr(info),
	}
}

func buildProviderDetail(
	info agentlib.HarnessInfo,
	signal agent.RoutingSignalSnapshot,
	outcomes []agent.RoutingOutcome,
	burnSummaries []agent.BurnSummary,
	now time.Time,
) ProviderDetail {
	outcomes7d := filterProviderOutcomes(outcomes, info.Name, now, 7)
	outcomes30d := filterProviderOutcomes(outcomes, info.Name, now, 30)
	perf := computeProviderPerformance(outcomes7d)
	sources := collectProviderSignalSources(signal, len(outcomes7d) > 0)

	var freshnessTS string
	if ts := providerFreshnessTS(signal, outcomes7d); !ts.IsZero() {
		freshnessTS = ts.UTC().Format(time.RFC3339)
	}

	models := buildModelQuotaList(info, signal)
	historicalUsage := computeProviderHistoricalUsage(info, signal, outcomes7d, outcomes30d)
	burnEstimate := computeProviderBurnEstimate(info, burnSummaries, historicalUsage, signal)

	statusStr := providerStatusStrInfo(info)
	return ProviderDetail{
		Harness:         info.Name,
		DisplayName:     harnessDisplayName(info.Name),
		Status:          statusStr,
		AuthState:       providerAuthStateStr(signal),
		Models:          models,
		HistoricalUsage: historicalUsage,
		BurnEstimate:    burnEstimate,
		RoutingSignals: ProviderRoutingSignals{
			Availability: statusStr,
			RequestFit:   providerRequestFitStrInfo(info),
			CostEstimate: "unknown",
			Performance:  perf,
		},
		SignalSources: sources,
		FreshnessTS:   freshnessTS,
	}
}

func buildModelQuotaList(info agentlib.HarnessInfo, signal agent.RoutingSignalSnapshot) []ProviderModelQuota {
	models := harnessDefaultModels(info.Name)
	if len(models) == 0 {
		return []ProviderModelQuota{}
	}

	quotaState := providerQuotaHeadroomStr(signal)
	sourceEnum := signalSourceAPIEnum(signal.Source.Kind)
	var sourceNote string
	if quotaState == "unknown" && info.Name == "claude" {
		sourceNote = "no stable non-PTY quota source confirmed"
	}

	result := make([]ProviderModelQuota, 0, len(models))
	for _, m := range models {
		result = append(result, ProviderModelQuota{
			Model:         m,
			QuotaHeadroom: quotaState,
			Source:        sourceEnum,
			SourceNote:    sourceNote,
		})
	}
	return result
}

func computeProviderHistoricalUsage(
	info agentlib.HarnessInfo,
	signal agent.RoutingSignalSnapshot,
	outcomes7d []agent.RoutingOutcome,
	outcomes30d []agent.RoutingOutcome,
) *ProviderHistoricalUsage {
	window7d := usageWindowFromSignalOrOutcomes(info, signal, outcomes7d)
	window30d := usageWindowFromOutcomes(info, outcomes30d)
	if window7d == nil && window30d == nil {
		return nil
	}
	return &ProviderHistoricalUsage{
		Window7D:  window7d,
		Window30D: window30d,
	}
}

func usageWindowFromSignalOrOutcomes(
	info agentlib.HarnessInfo,
	signal agent.RoutingSignalSnapshot,
	outcomes []agent.RoutingOutcome,
) *ProviderUsageWindow {
	// Prefer provider-native signal if it has token data.
	if signal.HistoricalUsage.TotalTokens > 0 || signal.HistoricalUsage.InputTokens > 0 {
		w := &ProviderUsageWindow{
			InputTokens:  signal.HistoricalUsage.InputTokens,
			OutputTokens: signal.HistoricalUsage.OutputTokens,
			TotalTokens:  signal.HistoricalUsage.TotalTokens,
		}
		if info.IsSubscription || info.IsLocal {
			w.CostUSD = 0
			if info.IsSubscription {
				w.CostNote = "subscription plan; per-token cost not billed"
			}
		} else {
			w.CostUSD = -1
		}
		return w
	}
	return usageWindowFromOutcomes(info, outcomes)
}

func usageWindowFromOutcomes(info agentlib.HarnessInfo, outcomes []agent.RoutingOutcome) *ProviderUsageWindow {
	if len(outcomes) == 0 {
		return nil
	}
	var inTok, outTok int
	var costUSD float64
	hasCost := false
	for _, o := range outcomes {
		inTok += o.InputTokens
		outTok += o.OutputTokens
		if o.CostUSD > 0 {
			costUSD += o.CostUSD
			hasCost = true
		}
	}
	if inTok == 0 && outTok == 0 {
		return nil
	}
	w := &ProviderUsageWindow{
		InputTokens:  inTok,
		OutputTokens: outTok,
		TotalTokens:  inTok + outTok,
	}
	if info.IsSubscription || info.IsLocal {
		w.CostUSD = 0
		if info.IsSubscription {
			w.CostNote = "subscription plan; per-token cost not billed"
		}
	} else if hasCost {
		w.CostUSD = costUSD
	} else {
		w.CostUSD = -1
	}
	return w
}

func computeProviderBurnEstimate(
	info agentlib.HarnessInfo,
	burnSummaries []agent.BurnSummary,
	usage *ProviderHistoricalUsage,
	signal agent.RoutingSignalSnapshot,
) *ProviderBurnEstimate {
	if !info.IsSubscription {
		return nil
	}

	// Find the most recent burn summary for this harness.
	var latestBurn *agent.BurnSummary
	for i := range burnSummaries {
		if burnSummaries[i].Harness == info.Name {
			if latestBurn == nil || burnSummaries[i].ObservedAt.After(latestBurn.ObservedAt) {
				latestBurn = &burnSummaries[i]
			}
		}
	}

	// Derive daily token rate from 7d window (DDx-observed or provider-native).
	dailyTokenRate := -1.0
	if usage != nil && usage.Window7D != nil && usage.Window7D.TotalTokens > 0 {
		dailyTokenRate = float64(usage.Window7D.TotalTokens) / 7.0
	}

	// Require at least one data source before emitting a burn estimate.
	if latestBurn == nil && dailyTokenRate < 0 {
		return nil
	}

	// Determine source attribution.
	sourceEnum := signalSourceAPIEnum(signal.Source.Kind)
	var sourceStr string
	if latestBurn != nil && dailyTokenRate >= 0 {
		if sourceEnum != "none" {
			sourceStr = sourceEnum + "+ddx-metrics"
		} else {
			sourceStr = "ddx-metrics"
		}
	} else if latestBurn != nil {
		if sourceEnum != "none" {
			sourceStr = sourceEnum
		} else {
			sourceStr = "ddx-metrics"
		}
	} else {
		sourceStr = "ddx-metrics"
	}

	subscriptionBurn := "unknown"
	confidence := "low"
	var freshnessTS string

	if latestBurn != nil {
		switch {
		case latestBurn.BurnIndex >= 0.8:
			subscriptionBurn = "high"
		case latestBurn.BurnIndex >= 0.5:
			subscriptionBurn = "moderate"
		case latestBurn.BurnIndex >= 0.1:
			subscriptionBurn = "low"
		}
		switch {
		case latestBurn.Confidence >= 0.8:
			confidence = "high"
		case latestBurn.Confidence >= 0.5:
			confidence = "medium"
		}
		if !latestBurn.ObservedAt.IsZero() {
			freshnessTS = latestBurn.ObservedAt.UTC().Format(time.RFC3339)
		}
	}

	return &ProviderBurnEstimate{
		DailyTokenRate:   dailyTokenRate,
		SubscriptionBurn: subscriptionBurn,
		Source:           sourceStr,
		Confidence:       confidence,
		FreshnessTS:      freshnessTS,
	}
}

// ---- Utility functions ----

// listHarnessInfos returns the harness inventory via the agent service.
// Replaces the older in-package harness inventory.
func listHarnessInfos(ctx context.Context, workDir string) ([]agentlib.HarnessInfo, error) {
	if ctx == nil {
		ctx = context.Background()
	}
	svc, err := agent.NewServiceFromWorkDir(workDir)
	if err != nil {
		return nil, err
	}
	return svc.ListHarnesses(ctx)
}

// findHarnessInfo locates a HarnessInfo in the slice by name.
func findHarnessInfo(infos []agentlib.HarnessInfo, name string) (agentlib.HarnessInfo, bool) {
	for i := range infos {
		if infos[i].Name == name {
			return infos[i], true
		}
	}
	return agentlib.HarnessInfo{}, false
}

// harnessDefaultModels returns the well-known default model(s) for a harness.
// Mirrors the historical in-package default model fields used by
// the provider detail endpoint. Empty slice means "no default model published".
func harnessDefaultModels(name string) []string {
	switch name {
	case "codex":
		return []string{"gpt-5.4"}
	case "claude":
		return []string{"claude-sonnet-4-6"}
	case "virtual":
		return []string{"recorded"}
	default:
		return nil
	}
}

// metricsStoreForWorkDir returns a RoutingMetricsStore using the project's
// configured session log dir resolved against workingDir.
func metricsStoreForWorkDir(workingDir string) *agent.RoutingMetricsStore {
	logDir := agent.SessionLogDirForWorkDir(workingDir)
	if logDir == "" {
		logDir = agent.DefaultLogDir
	}
	if !filepath.IsAbs(logDir) {
		logDir = filepath.Join(workingDir, logDir)
	}
	return agent.NewRoutingMetricsStore(logDir)
}

// filterProviderOutcomes returns outcomes for a given harness within the last windowDays days.
func filterProviderOutcomes(outcomes []agent.RoutingOutcome, harnessName string, now time.Time, windowDays int) []agent.RoutingOutcome {
	cutoff := now.Add(-time.Duration(windowDays) * 24 * time.Hour)
	result := make([]agent.RoutingOutcome, 0)
	for _, o := range outcomes {
		if o.Harness == harnessName && o.ObservedAt.After(cutoff) {
			result = append(result, o)
		}
	}
	return result
}

// computeProviderPerformance computes latency percentiles and success rate from outcomes.
// Returns -1 sentinels when sample_count < 3 per FEAT-014.
func computeProviderPerformance(outcomes []agent.RoutingOutcome) ProviderPerformance {
	perf := ProviderPerformance{
		P50LatencyMS: -1,
		P95LatencyMS: -1,
		SuccessRate:  -1,
		SampleCount:  len(outcomes),
		Window:       "7d",
	}
	if len(outcomes) < 3 {
		return perf
	}
	var successCount int
	latencies := make([]int, 0, len(outcomes))
	for _, o := range outcomes {
		if o.Success {
			successCount++
		}
		latencies = append(latencies, o.LatencyMS)
	}
	perf.SuccessRate = float64(successCount) / float64(len(outcomes))
	sort.Ints(latencies)
	perf.P50LatencyMS = latencies[len(latencies)/2]
	p95Idx := int(float64(len(latencies)-1) * 0.95)
	perf.P95LatencyMS = latencies[p95Idx]
	return perf
}

// collectProviderSignalSources builds the signal_sources array from the snapshot and metrics presence.
// Defined values per FEAT-014: native-session-jsonl, stats-cache, ddx-metrics, none.
func collectProviderSignalSources(signal agent.RoutingSignalSnapshot, hasMetrics bool) []string {
	seen := map[string]bool{}
	result := []string{}
	if signal.Source.Kind != "" {
		if enum := signalSourceAPIEnum(signal.Source.Kind); enum != "none" {
			seen[enum] = true
			result = append(result, enum)
		}
	}
	if hasMetrics && !seen["ddx-metrics"] {
		result = append(result, "ddx-metrics")
		seen["ddx-metrics"] = true
	}
	if len(result) == 0 {
		result = []string{"none"}
	}
	return result
}

// providerFreshnessTS returns the oldest contributing signal timestamp.
// Returns zero time when no signals exist (caller omits the field per FEAT-014).
func providerFreshnessTS(signal agent.RoutingSignalSnapshot, outcomes []agent.RoutingOutcome) time.Time {
	var oldest time.Time
	if !signal.Source.ObservedAt.IsZero() {
		oldest = signal.Source.ObservedAt
	}
	for _, o := range outcomes {
		if oldest.IsZero() || o.ObservedAt.Before(oldest) {
			oldest = o.ObservedAt
		}
	}
	return oldest
}

// providerStatusStrInfo maps a HarnessInfo to the API status string.
func providerStatusStrInfo(info agentlib.HarnessInfo) string {
	if info.Name == "" {
		return "unknown"
	}
	if info.Available {
		return "available"
	}
	return "unavailable"
}

// providerRequestFitStrInfo returns request_fit from harness availability.
func providerRequestFitStrInfo(info agentlib.HarnessInfo) string {
	if info.Available {
		return "capable"
	}
	return "unknown"
}

// providerAuthStateStr infers auth state from signal source and quota data.
// Per FEAT-014: probe fails or is not implemented → "unknown".
func providerAuthStateStr(signal agent.RoutingSignalSnapshot) string {
	// A non-trivial quota state means the harness responded with real data → authenticated.
	state := signal.CurrentQuota.State
	if state == "ok" || state == "blocked" {
		return "authenticated"
	}
	// A live signal from a native source (not docs-only/unknown) → authenticated.
	kind := signal.Source.Kind
	if kind != "" && kind != "docs-only" && kind != "unknown" && signal.Source.Freshness != "unknown" {
		return "authenticated"
	}
	return "unknown"
}

// providerQuotaHeadroomStr maps CurrentQuota.State to the API enum.
// Returns "unknown" when no trustworthy live source exists per FEAT-014.
func providerQuotaHeadroomStr(signal agent.RoutingSignalSnapshot) string {
	switch signal.CurrentQuota.State {
	case "ok":
		return "ok"
	case "blocked":
		return "blocked"
	default:
		return "unknown"
	}
}

		try {
			const res = await modelsClient.request<{
				refreshProviderModels: ProviderModelsResult;
			}>(REFRESH_PROVIDER_MODELS_MUTATION, { name: row.name, kind: row.kind });
			modelsByKey[key] = res.refreshProviderModels;
			expanded[key] = true;
		} catch (e) {
			modelsError[key] = e instanceof Error ? e.message : String(e);
		} finally {
			modelsLoading[key] = false;
		}
	}

	function toggleExpanded(row: ProviderStatus): void {
		const key = rowKey(row);
		const next = !expanded[key];
		expanded[key] = next;
		if (next && !modelsByKey[key] && !modelsLoading[key]) {
			void loadModels(row);
		}
	}

	$effect(() => {
		if (!loading && firstPaintAt === null) {
			firstPaintAt = Date.now();
		}
	});

	// Polling interval for live row patching after first paint. Chosen to be
	// short enough that probe results surface within the 5s AC budget but long
	// enough to not hammer the server. AC 1: rows patch within 5s of probe
	// completion — since the resolver returns cached rows updated asynchronously
	// by refreshProviderStatuses, polling here is sufficient to reflect them.
	const POLL_INTERVAL_MS = 2500;
	let pollTimer: ReturnType<typeof setInterval> | null = null;

	async function refresh(client: ReturnType<typeof createClient>) {
		const result = await client.request<{
			providerStatuses: ProviderStatus[];
			harnessStatuses: ProviderStatus[];
		}>(PROVIDER_STATUSES_QUERY);
		rows = [...(result.providerStatuses ?? []), ...(result.harnessStatuses ?? [])];
	}

	onMount(() => {
		const client = createClient();
		// First paint: provider + harness rows. defaultRouteStatus fires in
		// parallel via a separate query so a slow route-resolver can't delay
		// the table from rendering. AC 1: table interactive within 500ms.
		refresh(client)
			.catch((e) => {
				error = e instanceof Error ? e.message : String(e);
			})
			.finally(() => {
				loading = false;
			});

		client
			.request<{ defaultRouteStatus: DefaultRouteStatus | null }>(DEFAULT_ROUTE_QUERY)
			.then((res) => {
				defaultRoute = res.defaultRouteStatus ?? null;
			})
			.catch(() => {
				// Non-fatal: the default-route widget is informational only.
			});

		pollTimer = setInterval(() => {
			refresh(client).catch(() => {
				// Polling errors are transient; keep the last-known rows.
			});
		}, POLL_INTERVAL_MS);

		return () => {
			if (pollTimer != null) {
				clearInterval(pollTimer);
				pollTimer = null;
			}
		};
	});

	function statusClass(row: ProviderStatus): string {
		if (row.reachable) return 'text-status-closed';
		const lower = row.status.toLowerCase();
		if (
			lower.includes('connected') ||
			lower === 'available' ||
			lower.includes('api key configured')
		) {
			return 'text-status-closed';
		}
		if (
			lower.includes('cooldown') ||
			lower.includes('unreachable') ||
			lower.includes('error') ||
			lower === 'unavailable' ||
			lower.startsWith('unavailable')
		) {
			return 'text-status-failed';
		}
		return 'text-status-in-progress';
	}

	function formatTokens(n: number | null | undefined): string {
		if (n == null) return '—';
		if (n < 1000) return `${n}`;
		if (n < 1_000_000) return `${(n / 1000).toFixed(1)}k`;
		return `${(n / 1_000_000).toFixed(2)}M`;
	}

	function utilizationPct(usage: ProviderUsage | null, quota: ProviderQuota | null): number | null {
		if (!usage || !quota) return null;
		if (quota.ceilingTokens == null || quota.ceilingTokens <= 0) return null;
		const window = quota.ceilingWindowSeconds ?? 60;
		// Choose the usage field that matches the ceiling window (1h / 24h).
		const usedTokens = window <= 3600 ? usage.tokensUsedLastHour : usage.tokensUsedLast24h;
		if (usedTokens == null) return null;
		return Math.min(100, Math.round((usedTokens * 100) / quota.ceilingTokens));
	}

	function sparklineMax(values: number[]): number {
		let m = 0;
		for (const v of values) if (v > m) m = v;
		return m === 0 ? 1 : m;
	}

	function sparkBarHeight(value: number, max: number): string {
		const pct = Math.round((value * 100) / max);
		return `${Math.max(2, pct)}%`;
	}

	function detailHref(row: ProviderStatus): string {
		const nodeId = $page.params.nodeId;
		return `/nodes/${nodeId}/providers/${encodeURIComponent(row.name)}`;
	}

	// Section toggle (Availability / Performance) is URL-driven via the Story 8
	// chip query-param schema (`?section=availability|performance`). Default
	// section is availability so the existing URL keeps working.
	let section = $derived<SectionKey>(
		($page.url.searchParams.get('section') as SectionKey | null) === 'performance'
			? 'performance'
			: 'availability'
	);
	let perfWindow = $derived<WindowKey>(
		(($page.url.searchParams.get('window') ?? 'W7D') as WindowKey)
	);

	function setSection(next: SectionKey): void {
		const params = new URLSearchParams($page.url.searchParams);
		if (next === 'availability') params.delete('section');
		else params.set('section', next);
		const search = params.toString();
		goto(search ? `?${search}` : $page.url.pathname, { replaceState: false });
	}

	function setWindow(next: WindowKey): void {
		const params = new URLSearchParams($page.url.searchParams);
		params.set('section', 'performance');
		if (next === 'W7D') params.delete('window');
		else params.set('window', next);
		goto(`?${params.toString()}`, { replaceState: false });
	}

	let perfRows = $state<AgentMetricsRow[]>([]);
	let perfLoading = $state(false);
	let perfError = $state<string | null>(null);
	let perfClient: ReturnType<typeof createClient> | null = null;

	async function loadPerformance(window: WindowKey): Promise<void> {
		if (!perfClient) perfClient = createClient();
		perfLoading = true;
		perfError = null;
		try {
			const res = await perfClient.request<{
				agentMetrics: { rows: AgentMetricsRow[] };
			}>(AGENT_METRICS_QUERY, { window });
			perfRows = res.agentMetrics?.rows ?? [];
		} catch (e) {
			perfError = e instanceof Error ? e.message : String(e);
		} finally {
			perfLoading = false;
		}
	}

	$effect(() => {
		if (section === 'performance') {
			void loadPerformance(perfWindow);
		}
	});

	function perfDrillHref(row: AgentMetricsRow): string {
		const nodeId = $page.params.nodeId;
		// Drill-through links use the Story 8 chip query-param schema
		// (lower-case key=value). `window` echoes the active selection so the
		// detail page can scope its trend queries to the same span.
		const win = WINDOW_LABEL[perfWindow];
		return `/nodes/${nodeId}/providers/${encodeURIComponent(row.key)}?window=${win}`;
	}

	function fmtPct(n: number): string {
		return `${Math.round(n * 100)}%`;
	}

	function fmtMs(n: number): string {
		if (n < 1000) return `${Math.round(n)}ms`;
		if (n < 60_000) return `${(n / 1000).toFixed(1)}s`;
		const m = Math.floor(n / 60_000);
		const s = Math.round((n % 60_000) / 1000);
		return `${m}m ${s}s`;
	}

	function fmtUsd(n: number | null): string {
		if (n == null) return '—';
		if (n === 0) return '$0';
		if (n < 0.01) return `$${n.toFixed(4)}`;
		return `$${n.toFixed(3)}`;
	}
</script>

